function matchSoundCloudUrl(url: string | undefined): boolean {
	if (!url) return false;
	return /^https?:\/\/(www\.)?soundcloud\.com\/[\w-]+(\/[\w-]+)*\/?(\?.*)?$/.test(url);
}
